previewCss:
.darma-loader-darma-custom-418 {color: var(--loader-color, #16a34a);
  --loader-secondary-color: var(--loader-secondary-color, #86efac);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 50px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: repeating-conic-gradient(#0000,currentColor 1deg 18deg,#0000 20deg 36deg);
  animation: darma-loader-darma-custom-418-l9 4s infinite linear;
  position: relative;
}.darma-loader-darma-custom-418::before{content: "";
  position: absolute;
  border-radius: 50%;
  inset:0;
  background: inherit;
  animation: inherit;
}@keyframes darma-loader-darma-custom-418-l9{100% {transform: rotate(.5turn)}}

